1	# class 命令实现机制详解
2	
3	## 核心问题：如何找到 heap 中所有类实例的地址和类型，并进行打印？
4	
5	`class` 命令是 OpenCoreAnalysisKit 最常用的功能之一，展示了堆遍历和对象识别的核心技术。
6	
7	---
8	
9	## 一、整体流程图
10	
11	```mermaid
12	graph TB
13	    A[class 命令] --> B{参数解析}
14	    B -->|指定类名| C[搜索特定类]
15	    B -->|无参数| D[列出所有类]
16	    B -->|地址参数| E[直接访问]
17	    
18	    C --> F[ForeachObjects 堆遍历]
19	    D --> F
20	    E --> G[验证地址]
21	    
22	    F --> H[Space::Walk 逐空间遍历]
23	    H --> I[按 8 字节对齐遍历]
24	    I --> J{对象验证}
25	    
26	    J -->|IsValid?| K{IsClass?}
27	    K -->|是| L[PrintClass 回调]
28	    K -->|否| M[跳过]
29	    J -->|否| M
30	    
31	    L --> N{类名匹配?}
32	    N -->|是| O[PrintPrettyClassContent]
33	    N -->|否| P[继续遍历]
34	    
35	    O --> Q[输出类信息]
36	    Q --> R[字段/方法/接口]
37	    
38	    style F fill:#f9f,stroke:#333,stroke-width:4px
39	    style H fill:#9f9,stroke:#333,stroke-width:4px
40	    style J fill:#ff9,stroke:#333,stroke-width:2px
41	```
42	
43	---
44	
45	## 二、命令入口：prepare() 和 main()
46	
47	### 2.1 参数解析（prepare）
48	
49	```cpp
50	int ClassCommand::prepare(int argc, char* const argv[]) {
51	    // 1. 前置检查
52	    if (!CoreApi::IsReady() || !Android::IsSdkReady())
53	        return Command::FINISH;
54	
55	    // 2. 初始化选项
56	    options.dump_all = true;           // 是否列出所有类
57	    options.show_flag = 0;             // 显示选项标志
58	    options.format_hex = false;        // 是否十六进制显示
59	    options.obj_each_flags = 0;        // 对象类型过滤
60	    options.total_classes = 0;         // 类计数器
61	
62	    // 3. 解析命令行参数
63	    while ((opt = getopt_long(argc, argv, "msifx", long_options, ...)) != -1) {
64	        switch (opt) {
65	            case 'm': options.show_flag |= SHOW_METHOD;    // 显示方法
66	            case 's': options.show_flag |= SHOW_STATIC;    // 显示静态字段
67	            case 'i': options.show_flag |= SHOW_IMPL;      // 显示实现的接口
68	            case 'f': options.show_flag |= SHOW_FIELD;     // 显示实例字段
69	            case 'x': options.format_hex = true;           // 十六进制格式
70	            case 1:   options.obj_each_flags |= EACH_APP_OBJECTS;     // 应用对象
71	            case 2:   options.obj_each_flags |= EACH_ZYGOTE_OBJECTS;  // Zygote 对象
72	            case 3:   options.obj_each_flags |= EACH_IMAGE_OBJECTS;   // Image 对象
73	            case 4:   options.obj_each_flags |= EACH_FAKE_OBJECTS;    // 伪造对象
74	        }
75	    }
76	
77	    // 4. 默认行为：遍历所有类型的对象
78	    if (!options.obj_each_flags) {
79	        options.obj_each_flags = EACH_APP_OBJECTS | EACH_ZYGOTE_OBJECTS 
80	                               | EACH_IMAGE_OBJECTS | EACH_FAKE_OBJECTS;
81	    }
82	
83	    // 5. 如果有参数（类名或地址），则不是 dump_all 模式
84	    if (options.optind < argc) {
85	        options.dump_all = false;
86	        options.show_flag = !options.show_flag ? SHOW_ALL : options.show_flag;
87	    }
88	
89	    // 6. 准备 Android 运行时
90	    Android::Prepare();
91	    
92	    // 7. 在子进程执行（避免崩溃）
93	    return Command::ONCHLD;
94	}
95	```
96	
97	**参数示例**：
98	```bash
99	# 列出所有类
100	class
101	
102	# 搜索特定类
103	class java.lang.String
104	
105	# 显示类的字段和方法
106	class java.lang.String -f -m
107	
108	# 只搜索应用堆中的类
109	class --app java.util.HashMap
110	
111	# 直接访问类对象地址
112	class 0x71c530a0 -f -s -m
113	```
114	
115	### 2.2 主逻辑（main）
116	
117	```cpp
118	int ClassCommand::main(int argc, char* const argv[]) {
119	    const char* classname = argv[options.optind];
120	    
121	    // 定义回调函数
122	    auto callback = [&](art::mirror::Object& object) -> bool {
123	        return PrintClass(object, classname);
124	    };
125	
126	    try {
127	        if (!options.dump_all) {
128	            // 模式 1: 尝试将参数解析为地址
129	            art::mirror::Object obj = Utils::atol(argv[options.optind]);
130	            
131	            if (obj.Ptr() && obj.IsValid() && obj.IsClass()) {
132	                // 直接访问该地址的类对象
133	                art::mirror::Class thiz = obj;
134	                PrintPrettyClassContent(thiz, options);
135	            } else {
136	                // 参数是类名，搜索整个堆
137	                Android::ForeachObjects(callback, options.obj_each_flags, false);
138	            }
139	        } else {
140	            // 模式 2: 列出所有类
141	            Android::ForeachObjects(callback, options.obj_each_flags, false);
142	        }
143	    } catch(InvalidAddressException& e) {
144	        LOGW("The statistical process was interrupted!\n");
145	    }
146	    return 0;
147	}
148	```
149	
150	---
151	
152	## 三、核心机制：ForeachObjects 堆遍历
153	
154	### 3.1 顶层入口
155	
156	```cpp
157	// android/android.cpp
158	void Android::ForeachObjects(
159	    std::function<bool (art::mirror::Object& object)> fn,
160	    int flag,    // 对象类型过滤标志
161	    bool check   // 是否验证对象有效性
162	) {
163	    art::Runtime& runtime = art::Runtime::Current();
164	    art::gc::Heap& heap = runtime.GetHeap();
165	
166	    // 定义遍历函数
167	    auto walkfn = [&](art::gc::space::Space* space) {
168	        try {
169	            // 遍历该空间的所有对象
170	            space->Walk([&](art::mirror::Object& object) {
171	                // 可选：验证对象有效性
172	                if (check && !object.IsValid())
173	                    return;
174	                
175	                // 调用用户回调
176	                if (fn(object))
177	                    throw art::StopIteratorException();
178	            });
179	        } catch(InvalidAddressException& e) {
180	            LOGW("Space %s walking interrupted\n", space->GetName());
181	        } catch(art::StopIteratorException& e) {
182	            throw e;  // 用户主动停止遍历
183	        }
184	    };
185	
186	    // 遍历连续空间（ContinuousSpace）
187	    for (const auto& space : heap.GetContinuousSpaces()) {
188	        if (space->IsImageSpace()) {
189	            if (flag & EACH_IMAGE_OBJECTS) walkfn(space.get());
190	        } else if (space->IsZygoteSpace()) {
191	            if (flag & EACH_ZYGOTE_OBJECTS) walkfn(space.get());
192	        } else if (space->IsRegionSpace() || space->IsBumpPointerSpace()) {
193	            if (flag & EACH_APP_OBJECTS) walkfn(space.get());
194	        } else if (space->IsMallocSpace()) {
195	            if (space->IsRosAllocSpace() || space->IsDlMallocSpace()) {
196	                if (flag & EACH_APP_OBJECTS) walkfn(space.get());
197	            }
198	        } else if (space->IsFakeSpace()) {
199	            if (flag & EACH_FAKE_OBJECTS) walkfn(space.get());
200	        }
201	    }
202	
203	    // 遍历不连续空间（DiscontinuousSpace - 大对象空间）
204	    for (const auto& space : heap.GetDiscontinuousSpaces()) {
205	        if (flag & EACH_APP_OBJECTS) walkfn(space.get());
206	    }
207	}
208	```
209	
210	### 3.2 Space::Walk() - 单个空间遍历
211	
212	```cpp
213	// android/art/runtime/gc/space/space.cpp
214	void ContinuousSpace::Walk(std::function<void (Object&)> callback) {
215	    uint64_t begin = Begin();  // 空间起始地址
216	    uint64_t end = End();      // 空间结束地址
217	    
218	    // 按 8 字节对齐遍历（kObjectAlignment = 8）
219	    uint64_t current = begin;
220	    
221	    while (current < end) {
222	        try {
223	            // 1. 创建 Object 对象
224	            art::mirror::Object obj(current);
225	            
226	            // 2. 验证对象有效性
227	            if (!obj.IsValid()) {
228	                // 对象无效，跳到下一个可能的位置
229	                current = obj.NextValidOffset();
230	                continue;
231	            }
232	            
233	            // 3. 调用回调函数
234	            callback(obj);
235	            
236	            // 4. 移动到下一个对象
237	            uint32_t obj_size = obj.SizeOf();
238	            current += RoundUp(obj_size, kObjectAlignment);
239	            
240	        } catch(InvalidAddressException& e) {
241	            // 内存访问失败，尝试跳过
242	            current += kObjectAlignment;
243	        }
244	    }
245	}
246	```
247	
248	**关键点**：
249	- **8 字节对齐**：所有对象按 8 字节边界对齐
250	- **对象大小计算**：`SizeOf()` 多态方法，根据对象类型计算大小
251	- **异常恢复**：单个对象访问失败不影响整体遍历
252	
253	---
254	
255	## 四、对象识别：IsValid() 和 IsClass()
256	
257	### 4.1 对象有效性验证
258	
259	```cpp
260	// android/art/runtime/mirror/object.h
261	bool Object::IsValid() {
262	    // 1. 检查地址非空
263	    if (!Ptr()) return false;
264	    
265	    // 2. 读取 klass_ 字段（压缩引用）
266	    uint32_t klass_ref = klass();
267	    if (!klass_ref) return false;
268	    
269	    // 3. 检查不是 poison 值（已释放对象标记）
270	    if (klass_ref == 0xBADDB01D) return false;
271	    
272	    // 4. 构造 Class 对象并验证
273	    Class klass_obj(klass_ref);
274	    if (!klass_obj.Ptr()) return false;
275	    
276	    // 5. 验证 Class 对象本身有效
277	    if (!klass_obj.IsClass()) return false;
278	    
279	    // 6. 检查对象大小合理（>= 8 字节，<= 1MB）
280	    uint32_t size = SizeOf();
281	    if (size < kObjectAlignment) return false;
282	    if (size > 1024 * 1024) return false;  // 可选
283	    
284	    return true;
285	}
286	```
287	
288	**Object 内存布局**：
289	```
290	Object 对象：
291	+0x00: uint32_t klass_    (32位压缩引用指向 Class)
292	+0x04: uint32_t monitor_  (锁字)
293	+0x08: [字段数据...]
294	```
295	
296	### 4.2 类对象识别
297	
298	```cpp
299	bool Object::IsClass() {
300	    Class klass = GetClass();
301	    
302	    // 方式 1: 检查 klass 的 klass 是否指向 java.lang.Class
303	    Class klass_klass = klass.GetClass();
304	    
305	    // 方式 2: 检查特殊标志（SDK 24+）
306	    if (Android::Sdk() >= Android::N) {
307	        uint32_t flags = klass.GetClassFlags();
308	        return (flags & kClassFlagClass) != 0;
309	    }
310	    
311	    // 方式 3: 检查类名
312	    std::string descriptor = klass.PrettyDescriptor();
313	    return descriptor == "java.lang.Class";
314	}
315	```
316	
317	---
318	
319	## 五、PrintClass 回调：过滤和输出
320	
321	```cpp
322	bool ClassCommand::PrintClass(art::mirror::Object& object, const char* classname) {
323	    // 1. 过滤：只处理 Class 对象
324	    if (!object.IsClass())
325	        return false;
326	
327	    // 2. 转换为 Class 对象
328	    art::mirror::Class thiz = object;
329	    
330	    // 3. 模式判断
331	    if (options.dump_all) {
332	        // dump_all 模式：列出所有类
333	        options.total_classes++;
334	        LOGI("[%" PRId64 "] 0x%" PRIx64 " %s\n",
335	             options.total_classes, 
336	             thiz.Ptr(), 
337	             thiz.PrettyDescriptor().c_str());
338	        
339	        // 如果设置了显示选项，打印详细信息
340	        if (options.show_flag) 
341	            PrintPrettyClassContent(thiz, options);
342	            
343	    } else if (thiz.PrettyDescriptor() == classname) {
344	        // 搜索模式：类名匹配时打印
345	        PrintPrettyClassContent(thiz, options);
346	    }
347	
348	    return false;  // 继续遍历
349	}
350	```
351	
352	**输出示例（dump_all）**：
353	```
354	[1] 0x70209120 java.lang.Object
355	[2] 0x70209240 java.lang.Class
356	[3] 0x70209360 java.lang.String
357	[4] 0x70209480 java.lang.Integer
358	...
359	[1234] 0x12c05680 android.app.Activity
360	```
361	
362	---
363	
364	## 六、PrintPrettyClassContent：详细信息输出
365	
366	```cpp
367	void ClassCommand::PrintPrettyClassContent(Class& clazz, Options& options) {
368	    // ========== 1. 类声明 ==========
369	    Class super = clazz.GetSuperClass();
370	    if (super.Ptr()) {
371	        LOGI("%s class %s extends %s {\n",
372	             PrettyClassAccessFlags(clazz.GetAccessFlags()).c_str(),
373	             clazz.PrettyDescriptor().c_str(),
374	             super.PrettyDescriptor().c_str());
375	    } else {
376	        LOGI("%s class %s {\n", 
377	             PrettyClassAccessFlags(clazz.GetAccessFlags()).c_str(),
378	             clazz.PrettyDescriptor().c_str());
379	    }
380	
381	    // ========== 2. 实现的接口 ==========
382	    if (options.show_flag & SHOW_IMPL) {
383	        IfTable& iftable = clazz.GetIfTable();
384	        int32_t ifcount = iftable.Count();
385	        
386	        if (ifcount > 0) {
387	            LOGI("  // Implements:\n");
388	            for (int i = 0; i < ifcount; ++i) {
389	                Class interface = iftable.GetInterface(i);
390	                LOGI("    %s\n", interface.PrettyDescriptor().c_str());
391	            }
392	        }
393	    }
394	
395	    // ========== 3. 静态字段 ==========
396	    if (options.show_flag & SHOW_STATIC) {
397	        if (clazz.NumStaticFields() > 0) {
398	            LOGI("  // Class static fields:\n");
399	            
400	            // 收集所有静态字段
401	            std::vector<ArtField> fields;
402	            Android::ForeachStaticField(clazz, [&](ArtField& field) {
403	                fields.push_back(field);
404	                return false;
405	            });
406	            
407	            // 按偏移排序
408	            std::sort(fields.begin(), fields.end(), ArtField::Compare);
409	            
410	            // 打印每个静态字段
411	            for (auto& field : fields) {
412	                PrintCommand::PrintField(format, clazz, clazz, field, options);
413	            }
414	        }
415	    }
416	
417	    // ========== 4. 实例字段（包括继承的） ==========
418	    if (options.show_flag & SHOW_FIELD) {
419	        LOGI("  // Object instance fields:\n");
420	        
421	        Class current = clazz;
422	        do {
423	            // 打印当前类的字段
424	            if (current != clazz) {
425	                LOGI("  // extends %s\n", current.PrettyDescriptor().c_str());
426	            }
427	            
428	            std::vector<ArtField> fields;
429	            Android::ForeachInstanceField(current, [&](ArtField& field) {
430	                fields.push_back(field);
431	                return false;
432	            });
433	            
434	            std::sort(fields.begin(), fields.end(), ArtField::Compare);
435	            
436	            for (auto& field : fields) {
437	                LOGI("    [0x%03x] %s %s %s\n",
438	                     field.offset(),
439	                     PrettyFieldAccessFlags(field.access_flags()).c_str(),
440	                     field.PrettyTypeDescriptor().c_str(),
441	                     field.GetName());
442	            }
443	            
444	            // 向上遍历继承链
445	            current = current.GetSuperClass();
446	        } while (current.Ptr());
447	    }
448	
449	    // ========== 5. 方法 ==========
450	    if (options.show_flag & SHOW_METHOD) {
451	        if (clazz.NumMethods() > 0) {
452	            LOGI("  // Methods:\n");
453	            
454	            Android::ForeachArtMethods(clazz, [](ArtMethod& method) {
455	                LOGI("    [0x%" PRIx64 "] %s %s\n",
456	                     method.Ptr(),
457	                     PrettyMethodAccessFlags(method.access_flags()).c_str(),
458	                     method.ColorPrettyMethod().c_str());
459	                return false;
460	            });
461	        }
462	    }
463	
464	    LOGI("}\n");
465	}
466	```
467	
468	**输出示例**：
469	```
470	[0x71c530a0]
471	public final class android.net.wifi.WifiNetworkSpecifier extends android.net.NetworkSpecifier {
472	  // Implements:
473	    android.os.Parcelable
474	
