505	## 七、关键技术细节
506	
507	### 7.1 类名获取：PrettyDescriptor()
508	
509	```cpp
510	std::string Class::PrettyDescriptor() {
511	    // 1. 获取类名字符串
512	    String name_str = GetName();
513	    std::string descriptor = name_str.ToModifiedUtf8();
514	    
515	    // 2. 转换描述符格式
516	    // 内部格式: Ljava/lang/String;
517	    // 友好格式: java.lang.String
518	    
519	    if (descriptor[0] == 'L' && descriptor[descriptor.length()-1] == ';') {
520	        descriptor = descriptor.substr(1, descriptor.length()-2);
521	        std::replace(descriptor.begin(), descriptor.end(), '/', '.');
522	    }
523	    
524	    return descriptor;
525	}
526	```
527	
528	### 7.2 字段遍历（版本适配）
529	
530	```cpp
531	void Android::ForeachInstanceField(Class& clazz, std::function<bool(ArtField&)> fn) {
532	    if (LIKELY(Sdk() >= W)) {
533	        // SDK 36+: 字段统一存储
534	        uint32_t size = clazz.NumFields();
535	        ArtField field(clazz.GetFields(), clazz);
536	        
537	        for (int i = 0; i < size; i++) {
538	            if (!field.IsStatic())  // 过滤出实例字段
539	                if (fn(field)) break;
540	            field.MovePtr(SIZEOF(ArtField));
541	        }
542	    } else {
543	        // SDK < 36: 字段分离存储
544	        uint32_t size = clazz.NumInstanceFields();
545	        ArtField field(clazz.GetIFields(), clazz);
546	        
547	        for (int i = 0; i < size; i++) {
548	            if (fn(field)) break;
549	            field.MovePtr(SIZEOF(ArtField));
550	        }
551	    }
552	}
553	```
