555	### 7.3 对象大小计算
556	
557	```cpp
558	uint32_t Object::SizeOf() {
559	    Class klass = GetClass();
560	    
561	    if (IsArrayInstance()) {
562	        // 数组对象
563	        Array array(*this);
564	        uint32_t component_size = klass.GetComponentSize();
565	        uint32_t length = array.GetLength();
566	        return RoundUp(sizeof(Array) + component_size * length, 
567	                      kObjectAlignment);
568	    }
569	    
570	    if (klass.IsClass()) {
571	        // Class 对象（包含 vtable）
572	        Class clazz(*this);
573	        return clazz.GetClassSize();
574	    }
575	    
576	    if (klass.IsStringClass()) {
577	        // String 对象（内联字符数据）
578	        String str(*this);
579	        uint32_t length = str.GetLength();
580	        uint32_t char_size = str.IsCompressed() ? 1 : 2;
581	        return RoundUp(sizeof(String) + char_size * length, 
582	                      kObjectAlignment);
583	    }
584	    
585	    // 普通对象
586	    return RoundUp(klass.GetObjectSize(), kObjectAlignment);
587	}
