# class 命令实现机制详解

## 核心问题：如何找到 heap 中所有类实例的地址和类型，并进行打印？

`class` 命令是 OpenCoreAnalysisKit 最常用的功能之一，展示了堆遍历和对象识别的核心技术。

---

## 一、整体流程图

```mermaid
graph TB
    A[class 命令] --> B{参数解析}
    B -->|指定类名| C[搜索特定类]
    B -->|无参数| D[列出所有类]
    B -->|地址参数| E[直接访问]

    C --> F[ForeachObjects 堆遍历]
    D --> F
    E --> G[验证地址]

    F --> H[Space::Walk 逐空间遍历]
    H --> I[按 8 字节对齐遍历]
    I --> J{对象验证}

    J -->|IsValid?| K{IsClass?}
    K -->|是| L[PrintClass 回调]
    K -->|否| M[跳过]
    J -->|否| M

    L --> N{类名匹配?}
    N -->|是| O[PrintPrettyClassContent]
    N -->|否| P[继续遍历]

    O --> Q[输出类信息]
    Q --> R[字段/方法/接口]

    style F fill:#f9f,stroke:#333,stroke-width:4px
    style H fill:#9f9,stroke:#333,stroke-width:4px
    style J fill:#ff9,stroke:#333,stroke-width:2px
```

---

## 二、命令入口：prepare() 和 main()

### 2.1 参数解析（prepare）

```cpp
int ClassCommand::prepare(int argc, char* const argv[]) {
    // 1. 前置检查
    if (!CoreApi::IsReady() || !Android::IsSdkReady())
        return Command::FINISH;

    // 2. 初始化选项
    options.dump_all = true;           // 是否列出所有类
    options.show_flag = 0;             // 显示选项标志
    options.format_hex = false;        // 是否十六进制显示
    options.obj_each_flags = 0;        // 对象类型过滤
    options.total_classes = 0;         // 类计数器

    // 3. 解析命令行参数
    while ((opt = getopt_long(argc, argv, "msifx", long_options, ...)) != -1) {
        switch (opt) {
            case 'm': options.show_flag |= SHOW_METHOD;    // 显示方法
            case 's': options.show_flag |= SHOW_STATIC;    // 显示静态字段
            case 'i': options.show_flag |= SHOW_IMPL;      // 显示实现的接口
            case 'f': options.show_flag |= SHOW_FIELD;     // 显示实例字段
            case 'x': options.format_hex = true;           // 十六进制格式
            case 1:   options.obj_each_flags |= EACH_APP_OBJECTS;     // 应用对象
            case 2:   options.obj_each_flags |= EACH_ZYGOTE_OBJECTS;  // Zygote 对象
            case 3:   options.obj_each_flags |= EACH_IMAGE_OBJECTS;   // Image 对象
            case 4:   options.obj_each_flags |= EACH_FAKE_OBJECTS;    // 伪造对象
        }
    }

    // 4. 默认行为：遍历所有类型的对象
    if (!options.obj_each_flags) {
        options.obj_each_flags = EACH_APP_OBJECTS | EACH_ZYGOTE_OBJECTS 
                               | EACH_IMAGE_OBJECTS | EACH_FAKE_OBJECTS;
    }

    // 5. 如果有参数（类名或地址），则不是 dump_all 模式
    if (options.optind < argc) {
        options.dump_all = false;
        options.show_flag = !options.show_flag ? SHOW_ALL : options.show_flag;
    }

    // 6. 准备 Android 运行时
    Android::Prepare();

    // 7. 在子进程执行（避免崩溃）
    return Command::ONCHLD;
}
```

**参数示例**：
```bash
# 列出所有类
class

# 搜索特定类
class java.lang.String

# 显示类的字段和方法
class java.lang.String -f -m

# 只搜索应用堆中的类
class --app java.util.HashMap

# 直接访问类对象地址
class 0x71c530a0 -f -s -m
```

### 2.2 主逻辑（main）

```cpp
int ClassCommand::main(int argc, char* const argv[]) {
    const char* classname = argv[options.optind];

    // 定义回调函数
    auto callback = [&](art::mirror::Object& object) -> bool {
        return PrintClass(object, classname);
    };

    try {
        if (!options.dump_all) {
            // 模式 1: 尝试将参数解析为地址
            art::mirror::Object obj = Utils::atol(argv[options.optind]);

            if (obj.Ptr() && obj.IsValid() && obj.IsClass()) {
                // 直接访问该地址的类对象
                art::mirror::Class thiz = obj;
                PrintPrettyClassContent(thiz, options);
            } else {
                // 参数是类名，搜索整个堆
                Android::ForeachObjects(callback, options.obj_each_flags, false);
            }
        } else {
            // 模式 2: 列出所有类
            Android::ForeachObjects(callback, options.obj_each_flags, false);
        }
    } catch(InvalidAddressException& e) {
        LOGW("The statistical process was interrupted!\n");
    }
    return 0;
}
```

---

## 三、核心机制：ForeachObjects 堆遍历

### 3.1 顶层入口

```cpp
// android/android.cpp
void Android::ForeachObjects(
    std::function<bool (art::mirror::Object& object)> fn,
    int flag,    // 对象类型过滤标志
    bool check   // 是否验证对象有效性
) {
    art::Runtime& runtime = art::Runtime::Current();
    art::gc::Heap& heap = runtime.GetHeap();

    // 定义遍历函数
    auto walkfn = [&](art::gc::space::Space* space) {
        try {
            // 遍历该空间的所有对象
            space->Walk([&](art::mirror::Object& object) {
                // 可选：验证对象有效性
                if (check && !object.IsValid())
                    return;

                // 调用用户回调
                if (fn(object))
                    throw art::StopIteratorException();
            });
        } catch(InvalidAddressException& e) {
            LOGW("Space %s walking interrupted\n", space->GetName());
        } catch(art::StopIteratorException& e) {
            throw e;  // 用户主动停止遍历
        }
    };

    // 遍历连续空间（ContinuousSpace）
    for (const auto& space : heap.GetContinuousSpaces()) {
        if (space->IsImageSpace()) {
            if (flag & EACH_IMAGE_OBJECTS) walkfn(space.get());
        } else if (space->IsZygoteSpace()) {
            if (flag & EACH_ZYGOTE_OBJECTS) walkfn(space.get());
        } else if (space->IsRegionSpace() || space->IsBumpPointerSpace()) {
            if (flag & EACH_APP_OBJECTS) walkfn(space.get());
        } else if (space->IsMallocSpace()) {
            if (space->IsRosAllocSpace() || space->IsDlMallocSpace()) {
                if (flag & EACH_APP_OBJECTS) walkfn(space.get());
            }
        } else if (space->IsFakeSpace()) {
            if (flag & EACH_FAKE_OBJECTS) walkfn(space.get());
        }
    }

    // 遍历不连续空间（DiscontinuousSpace - 大对象空间）
    for (const auto& space : heap.GetDiscontinuousSpaces()) {
        if (flag & EACH_APP_OBJECTS) walkfn(space.get());
    }
}
```

### 3.2 Space::Walk() - 单个空间遍历

```cpp
// android/art/runtime/gc/space/space.cpp
void ContinuousSpace::Walk(std::function<void (Object&)> callback) {
    uint64_t begin = Begin();  // 空间起始地址
    uint64_t end = End();      // 空间结束地址

    // 按 8 字节对齐遍历（kObjectAlignment = 8）
    uint64_t current = begin;

    while (current < end) {
        try {
            // 1. 创建 Object 对象
            art::mirror::Object obj(current);

            // 2. 验证对象有效性
            if (!obj.IsValid()) {
                // 对象无效，跳到下一个可能的位置
                current = obj.NextValidOffset();
                continue;
            }

            // 3. 调用回调函数
            callback(obj);

            // 4. 移动到下一个对象
            uint32_t obj_size = obj.SizeOf();
            current += RoundUp(obj_size, kObjectAlignment);

        } catch(InvalidAddressException& e) {
            // 内存访问失败，尝试跳过
            current += kObjectAlignment;
        }
    }
}
```

**关键点**：
- **8 字节对齐**：所有对象按 8 字节边界对齐
- **对象大小计算**：`SizeOf()` 多态方法，根据对象类型计算大小
- **异常恢复**：单个对象访问失败不影响整体遍历

---

## 四、对象识别：IsValid() 和 IsClass()

### 4.1 对象有效性验证

```cpp
// android/art/runtime/mirror/object.h
bool Object::IsValid() {
    // 1. 检查地址非空
    if (!Ptr()) return false;

    // 2. 读取 klass_ 字段（压缩引用）
    uint32_t klass_ref = klass();
    if (!klass_ref) return false;

    // 3. 检查不是 poison 值（已释放对象标记）
    if (klass_ref == 0xBADDB01D) return false;

    // 4. 构造 Class 对象并验证
    Class klass_obj(klass_ref);
    if (!klass_obj.Ptr()) return false;

    // 5. 验证 Class 对象本身有效
    if (!klass_obj.IsClass()) return false;

    // 6. 检查对象大小合理（>= 8 字节，<= 1MB）
    uint32_t size = SizeOf();
    if (size < kObjectAlignment) return false;
    if (size > 1024 * 1024) return false;  // 可选

    return true;
}
```

**Object 内存布局**：
```
Object 对象：
+0x00: uint32_t klass_    (32位压缩引用指向 Class)
+0x04: uint32_t monitor_  (锁字)
+0x08: [字段数据...]
```

### 4.2 类对象识别

```cpp
bool Object::IsClass() {
    Class klass = GetClass();

    // 方式 1: 检查 klass 的 klass 是否指向 java.lang.Class
    Class klass_klass = klass.GetClass();

    // 方式 2: 检查特殊标志（SDK 24+）
    if (Android::Sdk() >= Android::N) {
        uint32_t flags = klass.GetClassFlags();
        return (flags & kClassFlagClass) != 0;
    }

    // 方式 3: 检查类名
    std::string descriptor = klass.PrettyDescriptor();
    return descriptor == "java.lang.Class";
}
```

---

## 五、PrintClass 回调：过滤和输出

```cpp
bool ClassCommand::PrintClass(art::mirror::Object& object, const char* classname) {
    // 1. 过滤：只处理 Class 对象
    if (!object.IsClass())
        return false;

    // 2. 转换为 Class 对象
    art::mirror::Class thiz = object;

    // 3. 模式判断
    if (options.dump_all) {
        // dump_all 模式：列出所有类
        options.total_classes++;
        LOGI("[%" PRId64 "] 0x%" PRIx64 " %s\n",
             options.total_classes, 
             thiz.Ptr(), 
             thiz.PrettyDescriptor().c_str());

        // 如果设置了显示选项，打印详细信息
        if (options.show_flag) 
            PrintPrettyClassContent(thiz, options);

    } else if (thiz.PrettyDescriptor() == classname) {
        // 搜索模式：类名匹配时打印
        PrintPrettyClassContent(thiz, options);
    }

    return false;  // 继续遍历
}
```

**输出示例（dump_all）**：
```
[1] 0x70209120 java.lang.Object
[2] 0x70209240 java.lang.Class
[3] 0x70209360 java.lang.String
[4] 0x70209480 java.lang.Integer
...
[1234] 0x12c05680 android.app.Activity
```

---

## 六、PrintPrettyClassContent：详细信息输出

```cpp
void ClassCommand::PrintPrettyClassContent(Class& clazz, Options& options) {
    // ========== 1. 类声明 ==========
    Class super = clazz.GetSuperClass();
    if (super.Ptr()) {
        LOGI("%s class %s extends %s {\n",
             PrettyClassAccessFlags(clazz.GetAccessFlags()).c_str(),
             clazz.PrettyDescriptor().c_str(),
             super.PrettyDescriptor().c_str());
    } else {
        LOGI("%s class %s {\n", 
             PrettyClassAccessFlags(clazz.GetAccessFlags()).c_str(),
             clazz.PrettyDescriptor().c_str());
    }

    // ========== 2. 实现的接口 ==========
    if (options.show_flag & SHOW_IMPL) {
        IfTable& iftable = clazz.GetIfTable();
        int32_t ifcount = iftable.Count();

        if (ifcount > 0) {
            LOGI("  // Implements:\n");
            for (int i = 0; i < ifcount; ++i) {
                Class interface = iftable.GetInterface(i);
                LOGI("    %s\n", interface.PrettyDescriptor().c_str());
            }
        }
    }

    // ========== 3. 静态字段 ==========
    if (options.show_flag & SHOW_STATIC) {
        if (clazz.NumStaticFields() > 0) {
            LOGI("  // Class static fields:\n");

            // 收集所有静态字段
            std::vector<ArtField> fields;
            Android::ForeachStaticField(clazz, [&](ArtField& field) {
                fields.push_back(field);
                return false;
            });

            // 按偏移排序
            std::sort(fields.begin(), fields.end(), ArtField::Compare);

            // 打印每个静态字段
            for (auto& field : fields) {
                PrintCommand::PrintField(format, clazz, clazz, field, options);
            }
        }
    }

    // ========== 4. 实例字段（包括继承的） ==========
    if (options.show_flag & SHOW_FIELD) {
        LOGI("  // Object instance fields:\n");

        Class current = clazz;
        do {
            // 打印当前类的字段
            if (current != clazz) {
                LOGI("  // extends %s\n", current.PrettyDescriptor().c_str());
            }

            std::vector<ArtField> fields;
            Android::ForeachInstanceField(current, [&](ArtField& field) {
                fields.push_back(field);
                return false;
            });

            std::sort(fields.begin(), fields.end(), ArtField::Compare);

            for (auto& field : fields) {
                LOGI("    [0x%03x] %s %s %s\n",
                     field.offset(),
                     PrettyFieldAccessFlags(field.access_flags()).c_str(),
                     field.PrettyTypeDescriptor().c_str(),
                     field.GetName());
            }

            // 向上遍历继承链
            current = current.GetSuperClass();
        } while (current.Ptr());
    }

    // ========== 5. 方法 ==========
    if (options.show_flag & SHOW_METHOD) {
        if (clazz.NumMethods() > 0) {
            LOGI("  // Methods:\n");

            Android::ForeachArtMethods(clazz, [](ArtMethod& method) {
                LOGI("    [0x%" PRIx64 "] %s %s\n",
                     method.Ptr(),
                     PrettyMethodAccessFlags(method.access_flags()).c_str(),
                     method.ColorPrettyMethod().c_str());
                return false;
            });
        }
    }

    LOGI("}\n");
}
```

