#include "logger/log.h"
#include "command/core/cmd_sysroot.h"
#include "api/core.h"
#include "android.h"
#include <unistd.h>
#include <getopt.h>

int SysRootCommand::main(int argc, char* const argv[]) {
    if (!CoreApi::IsReady() || !(argc > 1))
        return 0;

    int opt;
    int root = MAP_ROOT | DEX_ROOT;
    int option_index = 0;
    optind = 0; // reset
    static struct option long_options[] = {
        {"map",  no_argument,       0,  0 },
        {"dex",  no_argument,       0,  1 },
        {0,      0,                 0,  0 },
    };

    while ((opt = getopt_long(argc, argv, "01",
                long_options, &option_index)) != -1) {
        switch (opt) {
            case 0:
                root &= ~DEX_ROOT;
                root |= MAP_ROOT;
                break;
            case 1:
                root &= ~MAP_ROOT;
                root |= DEX_ROOT;
                break;
        }
    }

    if (optind >= argc)
        return 0;

    return Load(argv[optind], root);
}

int SysRootCommand::Load(const char* path, int root) {
    if (!CoreApi::IsReady())
        return 0;

    if (root & MAP_ROOT)
        CoreApi::SysRoot(path);

    if (root & DEX_ROOT) {
        if (Android::IsSdkReady()) {
            Android::SysRoot(path);
        } else {
            LOGW("Android sdk no ready, You can enter command:\n         env config --sdk <version>\n");
        }
    }
    return 0;
}

void SysRootCommand::usage() {
    LOGI("Usage: sysroot <DIR_PATH>[:<PATH>:<PATH>] [OPTION]\n");
