    LOGI("Mmap segment [75dc4d4f8000, 75dc4d5d5000) /system/lib64/libandroid_runtime.so [0]\n");
    LOGI("...\n");
    ENTER();
    LOGI("core-parser> sysroot /system:/apex --dex\n");
